import{_ as a,o as n,c as s,a2 as t}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"SageAgent — Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/sage-agent/architecture.md","filePath":"research/agents/sage-agent/architecture.md"}'),i={name:"research/agents/sage-agent/architecture.md"};function l(o,e,r,p,c,d){return n(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="sageagent-—-architecture" tabindex="-1">SageAgent — Architecture <a class="header-anchor" href="#sageagent-—-architecture" aria-label="Permalink to &quot;SageAgent — Architecture&quot;">​</a></h1><h2 id="multi-agent-pipeline" tabindex="-1">Multi-Agent Pipeline <a class="header-anchor" href="#multi-agent-pipeline" aria-label="Permalink to &quot;Multi-Agent Pipeline&quot;">​</a></h2><p>SageAgent&#39;s core architecture is a sequential pipeline of five specialized agents, coordinated by an <code>AgentController</code> that serves as the main entry point for user requests.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>AgentController</span></span>
<span class="line"><span>  ├── TaskAnalysisAgent   — requirement understanding</span></span>
<span class="line"><span>  ├── PlanningAgent       — subtask decomposition</span></span>
<span class="line"><span>  ├── ExecutorAgent       — tool-assisted execution</span></span>
<span class="line"><span>  ├── ObservationAgent    — progress monitoring + feedback</span></span>
<span class="line"><span>  └── TaskSummaryAgent    — output generation</span></span></code></pre></div><p>Each agent inherits from <code>AgentBase</code>, which provides common infrastructure for LLM interaction, message handling, and state management.</p><h2 id="directory-layout" tabindex="-1">Directory Layout <a class="header-anchor" href="#directory-layout" aria-label="Permalink to &quot;Directory Layout&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>agents/</span></span>
<span class="line"><span>    agent/</span></span>
<span class="line"><span>        agent_controller.py      # Entry point, orchestrates pipeline</span></span>
<span class="line"><span>        agent_base.py            # Base class for all agents</span></span>
<span class="line"><span>        task_analysis_agent/     # Requirement analysis</span></span>
<span class="line"><span>        planning_agent/          # Task decomposition and planning</span></span>
<span class="line"><span>        executor_agent/          # Execution with tool access</span></span>
<span class="line"><span>        observation_agent/       # Progress evaluation + feedback loop</span></span>
<span class="line"><span>        task_summary_agent/      # Final summary generation</span></span>
<span class="line"><span>    tool/</span></span>
<span class="line"><span>        tool_base.py             # Tool interface</span></span>
<span class="line"><span>        tool_manager.py          # Registration, discovery, dispatch</span></span>
<span class="line"><span>        calculation_tool.py      # Built-in calculation tool</span></span>
<span class="line"><span>    professional_agents/         # Placeholder for domain-specific agents</span></span>
<span class="line"><span>    task/                        # Task data structures</span></span>
<span class="line"><span>    utils/                       # Shared utilities</span></span>
<span class="line"><span>examples/</span></span>
<span class="line"><span>    sage_demo.py                 # Streamlit web demo</span></span>
<span class="line"><span>mcp_servers/</span></span>
<span class="line"><span>    mcp_setting.json             # MCP server configuration</span></span></code></pre></div><h2 id="agentbase" tabindex="-1">AgentBase <a class="header-anchor" href="#agentbase" aria-label="Permalink to &quot;AgentBase&quot;">​</a></h2><p>All agents extend <code>AgentBase</code>, which likely provides:</p><ul><li>LLM client initialization and prompt management</li><li>Structured message input/output (normal + thinking types)</li><li>Common logging and error handling</li></ul><blockquote><p>Note: Specific <code>AgentBase</code> internals not deeply reviewed (Tier 3 analysis).</p></blockquote><h2 id="agentcontroller" tabindex="-1">AgentController <a class="header-anchor" href="#agentcontroller" aria-label="Permalink to &quot;AgentController&quot;">​</a></h2><p>The <code>AgentController</code> is the user-facing entry point. It:</p><ol><li>Accepts user input</li><li>Routes through the pipeline in sequence</li><li>Manages the feedback loop between ObservationAgent and PlanningAgent</li><li>Returns the final summary to the user</li></ol><h2 id="two-execution-modes" tabindex="-1">Two Execution Modes <a class="header-anchor" href="#two-execution-modes" aria-label="Permalink to &quot;Two Execution Modes&quot;">​</a></h2><p>SageAgent supports dual execution modes selectable at invocation time:</p><h3 id="deep-research-mode" tabindex="-1">Deep Research Mode <a class="header-anchor" href="#deep-research-mode" aria-label="Permalink to &quot;Deep Research Mode&quot;">​</a></h3><ul><li>Full multi-agent pipeline engagement</li><li>All five agents participate</li><li>Feedback loop enabled — ObservationAgent can send incomplete tasks back to PlanningAgent</li><li>Suitable for complex, multi-step research and analysis tasks</li></ul><h3 id="rapid-execution-mode" tabindex="-1">Rapid Execution Mode <a class="header-anchor" href="#rapid-execution-mode" aria-label="Permalink to &quot;Rapid Execution Mode&quot;">​</a></h3><ul><li>Lightweight, fast task completion</li><li>Likely bypasses or simplifies some pipeline stages</li><li>Designed for straightforward tasks that don&#39;t need iterative refinement</li><li>Reduced latency at the cost of less thorough analysis</li></ul><p>The mode selection mechanism is configured at the controller level, though the exact toggle API is not deeply documented in the public README.</p><h2 id="professional-agents-planned" tabindex="-1">Professional Agents (Planned) <a class="header-anchor" href="#professional-agents-planned" aria-label="Permalink to &quot;Professional Agents (Planned)&quot;">​</a></h2><p>The <code>professional_agents/</code> directory suggests a plugin system for domain-specialized agents. This is listed on the roadmap but appears to be in early stages. The concept would allow specialized agents (e.g., for code review, data analysis) to be plugged into the pipeline.</p><hr><p><em>Tier 3 analysis — architecture inferred primarily from README and directory structure.</em></p>`,25)])])}const h=a(i,[["render",l]]);export{u as __pageData,h as default};
